provider "aws" {
  region  = "us-gov-east-1"
  profile = "govcloud"
}

# S3 bucket in GovCloud
resource "aws_s3_bucket" "itar_data" {
  bucket = "my-itar-protected-bucket"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "itar_enc" {
  bucket = aws_s3_bucket.itar_data.bucket
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.itar_key.arn
    }
  }
}

# IAM role — note aws-us-gov partition in ARN
resource "aws_iam_role" "app_role" {
  name = "govcloud-app-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action    = "sts:AssumeRole"
      Effect    = "Allow"
      Principal = { Service = "ec2.amazonaws.com" }
    }]
  })
}

# Terraform: resolve partition dynamically
data "aws_partition" "current" {}
data "aws_region" "current" {}
data "aws_caller_identity" "current" {}

# Build ARN without hardcoding partition
locals {
  my_bucket_arn = "arn:${data.aws_partition.current.partition}:s3:::${var.bucket_name}"
  kms_key_arn   = "arn:${data.aws_partition.current.partition}:kms:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:key/${var.key_id}"
}

# SCP to restrict all actions to us-gov-east-1 only
{
  "Version": "2012-10-17",
  "Statement": [{
    "Sid": "DenyOutsideGovEast",
    "Effect": "Deny",
    "NotAction": [
      "iam:*",
      "sts:*",
      "organizations:*",
      "support:*"
    ],
    "Resource": "*",
    "Condition": {
      "StringNotEquals": {
        "aws:RequestedRegion": "us-gov-east-1"
      }
    }
  }]
}
